import{_ as s,c as n,o as a,d as e}from"./app.661b9247.js";const l="/FrontEndLearnNotes/assets/az1.514011a7.jpg",p="/FrontEndLearnNotes/assets/az2.ab817135.jpg",o="/FrontEndLearnNotes/assets/az3.6364ef82.jpg",r="/FrontEndLearnNotes/assets/az4.1e85f7be.jpg",c="/FrontEndLearnNotes/assets/az5.308c10d2.jpg",t="/FrontEndLearnNotes/assets/az6.73bedfbd.jpg",i="/FrontEndLearnNotes/assets/az7.5fc8fd24.jpg",d="/FrontEndLearnNotes/assets/az8.8889050f.jpg",y="/FrontEndLearnNotes/assets/az7.1.9fc4d059.jpg",m="/FrontEndLearnNotes/assets/yx1.5ff4b353.jpg",b="/FrontEndLearnNotes/assets/yx2.d81b8bae.jpg",B="/FrontEndLearnNotes/assets/khd1.d8148755.jpg",u="/FrontEndLearnNotes/assets/khd2.711704c9.jpg",h="/FrontEndLearnNotes/assets/khd3.5262eb13.jpg",g="/FrontEndLearnNotes/assets/khd4.9d0bee03.jpg",F="/FrontEndLearnNotes/assets/khd5.73309b31.jpg",_="/FrontEndLearnNotes/assets/khd6.a2fce361.jpg",C="/FrontEndLearnNotes/assets/khd7.93be4af0.jpg",f="/FrontEndLearnNotes/assets/xz1.103abd7e.jpg",j=JSON.parse('{"title":"MySQL下载安装和配置","description":"","frontmatter":{},"headers":[{"level":2,"title":"MySQL Community Server下载","slug":"mysql-community-server下载","link":"#mysql-community-server下载","children":[]},{"level":2,"title":"安装","slug":"安装","link":"#安装","children":[{"level":3,"title":"windows安装","slug":"windows安装","link":"#windows安装","children":[]}]},{"level":2,"title":"MySQL启动","slug":"mysql启动","link":"#mysql启动","children":[]},{"level":2,"title":"MySQL客户端连接","slug":"mysql客户端连接","link":"#mysql客户端连接","children":[{"level":3,"title":"方式1：MySQL 提供的客户端命令工具","slug":"方式1-mysql-提供的客户端命令工具","link":"#方式1-mysql-提供的客户端命令工具","children":[]},{"level":3,"title":"方式2：系统自带的命令行工具执行命令","slug":"方式2-系统自带的命令行工具执行命令","link":"#方式2-系统自带的命令行工具执行命令","children":[]},{"level":3,"title":"方式3：Navicat Premium数据库图形化界面管理软件(收费)","slug":"方式3-navicat-premium数据库图形化界面管理软件-收费","link":"#方式3-navicat-premium数据库图形化界面管理软件-收费","children":[]},{"level":3,"title":"方式4","slug":"方式4","link":"#方式4","children":[]}]},{"level":2,"title":"卸载MySQL数据库","slug":"卸载mysql数据库","link":"#卸载mysql数据库","children":[]},{"level":2,"title":"可能遇到的问题","slug":"可能遇到的问题","link":"#可能遇到的问题","children":[]}],"relativePath":"Document/数据库的使用/MySQL数据库/MySQL下载安装和配置.md","lastUpdated":1670531003000}'),A={name:"Document/数据库的使用/MySQL数据库/MySQL下载安装和配置.md"},L=e('<h1 id="mysql下载安装和配置" tabindex="-1">MySQL下载安装和配置 <a class="header-anchor" href="#mysql下载安装和配置" aria-hidden="true">#</a></h1><h2 id="mysql-community-server下载" tabindex="-1">MySQL Community Server下载 <a class="header-anchor" href="#mysql-community-server下载" aria-hidden="true">#</a></h2><p>1.下载地址：<a href="https://dev.mysql.com/downloads/" target="_blank" rel="noreferrer">MySQL :: MySQL Community Downloads</a></p><p>2.找到MySQL Community Server(默认是最新版本，且是zip压缩格式)：<a href="https://dev.mysql.com/downloads/mysql/" target="_blank" rel="noreferrer">MySQL :: Download MySQL Community Server</a></p><p>2.1 最新版本msi安装包格式-点击 ‘’Go to Download Page‘ 的图片：下载最大的msi安装包</p><p>3.如果要下载5.7版本，找到并点击右边文字连接：<a href="https://dev.mysql.com/downloads/mysql/5.7.html" target="_blank" rel="noreferrer">Looking for previous GA versions?</a></p><p>3.1 版本5 msi安装包格式也是-点击 ‘’Go to Download Page‘ 的图片：下载最大的msi安装包</p><p>中科大Mysql镜像：<a href="http://mirrors.ustc.edu.cn/mysql-ftp/Downloads/" target="_blank" rel="noreferrer">Index of /mysql-ftp/Downloads/ (ustc.edu.cn)</a></p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-hidden="true">#</a></h2><h3 id="windows安装" tabindex="-1">windows安装 <a class="header-anchor" href="#windows安装" aria-hidden="true">#</a></h3><p>双击运行mysql-installer-community-xxx.msi</p><p><img src="'+l+'" alt="az1.jpg"></p><h4 id="安装界面代表" tabindex="-1">安装界面代表 <a class="header-anchor" href="#安装界面代表" aria-hidden="true">#</a></h4><ul><li><p>“Developer Default”是开发者默认</p></li><li><p>“Server only”仅作为服务器安装</p></li><li><p>“Client only”仅作为客户端安装</p></li><li><p>“Full”是完整安装</p></li><li><p>“Custom”是自定义安装</p></li></ul><p>这里选择是 “Developer Default”是开发者默认，点击“Next”</p><p>来的第二个界面</p><p><img src="'+p+'" alt="az2.jpg"></p><p>点击下一步弹出弹窗，再点击Yes</p><p><img src="'+o+'" alt="az3.jpg"></p><p>点击 <code>Excute</code>，安装 MySQL 的相关组件，这个过程可能需要耗时几分钟</p><p><img src="'+r+'" alt="az4.jpg"></p><p>安装完成全部组件后，点击 <code>next</code></p><p>后面一路<code>next</code></p><p>来到<code>Accounts and Roles</code>页面</p><p><img src="'+c+'" alt="az5.jpg"></p><p>输入 MySQL 的 root 密码，谨记，设置完密码之后点击 <code>next</code></p><p><code>next</code>到最后 <code>Apply Configuration</code> 页面，</p><p><img src="'+t+'" alt="az6.jpg"></p><p>点击 <code>Execute</code> ，安装相关依赖包</p><p><img src="'+i+'" alt="az7.jpg"></p><p>相关组件和设置完成安装，点击<code>Finish</code>回到初始安装页</p><p>配置向导，如果不用配置就选择<code>Cancel</code>，需要配置向导就选择 <code>next</code></p><p><img src="'+d+'" alt="az8.jpg"></p><p>如果这里选择<code>Cancel</code>，弹出弹窗，选择<code>Yes</code>，至此，安装完成</p><p>如果是点击<code>next</code>，后面需要<strong>输入用户名和密码</strong>，点击<code>check</code>，检查是否正确。</p><p>成功了<code>next</code>才可点击</p><p><img src="'+y+'" alt="az7.1.jpg"></p><p>后面还需要Execute安装相关</p><p>最后<code>Finish</code>完成</p><h2 id="mysql启动" tabindex="-1">MySQL启动 <a class="header-anchor" href="#mysql启动" aria-hidden="true">#</a></h2><p>MySQL 安装完成之后会自动注册为系统服务，默认为启动状态，而且是开机自启的。</p><p>如果想要停止 MySQL 可通过 <code>win + R</code> 打开运行，输入 <code>services.msc</code> 找到 <code>MySQL</code> 进行停止。</p><p>或者通过指令（需要以管理员的身份执行）去操作：</p><p>启动：<code>net start mysql80</code><br> 停止：<code>net stop mysql80</code>.</p><p>1.查找cmd</p><p><img src="'+m+'" alt="yx1.jpg"></p><p>2.运行命令</p><p><img src="'+b+`" alt="yx2.jpg"></p><h2 id="mysql客户端连接" tabindex="-1">MySQL客户端连接 <a class="header-anchor" href="#mysql客户端连接" aria-hidden="true">#</a></h2><p>数据库相关命令：参考：<a href="https://blog.csdn.net/LCW0102/article/details/123835997" target="_blank" rel="noreferrer">MySql数据库命令大全</a></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 连接MySQL</span></span>
<span class="line"><span style="color:#ABB2BF;">mysql </span><span style="color:#D19A66;">-h主机地址</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-u用户名</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">－p用户密码</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 启动mysql服务器</span></span>
<span class="line"><span style="color:#ABB2BF;">net </span><span style="color:#98C379;">start</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">mysql</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 关闭mysql服务器</span></span>
<span class="line"><span style="color:#ABB2BF;">net </span><span style="color:#98C379;">stop</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">mysql</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 修改数据库密码</span></span>
<span class="line"><span style="color:#ABB2BF;">mysqladmin </span><span style="color:#D19A66;">-u用户名</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-p旧密码</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">password</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">新密码</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 创建数据库</span></span>
<span class="line"><span style="color:#ABB2BF;">create </span><span style="color:#98C379;">database</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 显示所有的数据库名</span></span>
<span class="line"><span style="color:#ABB2BF;">show </span><span style="color:#98C379;">databases</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">数据库名称</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 使用或切换数据库</span></span>
<span class="line"><span style="color:#ABB2BF;">use </span><span style="color:#98C379;">数据库名称</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 查询当前所在数据库</span></span>
<span class="line"><span style="color:#C678DD;">select</span><span style="color:#ABB2BF;"> </span><span style="color:#E06C75;">database</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 修改数据库编码格式</span></span>
<span class="line"><span style="color:#ABB2BF;">alter </span><span style="color:#98C379;">database</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># ***** 数据库中的表操作 *****</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 查看数据库中所有的表</span></span>
<span class="line"><span style="color:#ABB2BF;">show </span><span style="color:#98C379;">tables</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 查看指定表的创建结构</span></span>
<span class="line"><span style="color:#ABB2BF;">show </span><span style="color:#98C379;">create</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">table</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 将表中记录清空</span></span>
<span class="line"><span style="color:#ABB2BF;">delete </span><span style="color:#98C379;">from</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">表名</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 删除数据库</span></span>
<span class="line"><span style="color:#ABB2BF;">drop </span><span style="color:#98C379;">database</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">库名</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 删除表格</span></span>
<span class="line"><span style="color:#ABB2BF;">drop </span><span style="color:#98C379;">table</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">表名</span></span>
<span class="line"><span style="color:#ABB2BF;">或</span></span>
<span class="line"><span style="color:#ABB2BF;">drop </span><span style="color:#98C379;">table</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">if</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">exists</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">表名称</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">或</span></span>
<span class="line"><span style="color:#ABB2BF;">drop </span><span style="color:#98C379;">table</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">if</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">exists</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">表名称1,表名称2,…</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 删除说明：if exists是判断是否存在该表，若存在则进行删除，若不存在也不会报错，不是非必须写，但是不写的话，删除一个不存在的表就会有报错。删除表的时候可以一次性删除一个，也可以一次性删除多个表。</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 创建一个新表</span></span>
<span class="line"><span style="color:#ABB2BF;">create </span><span style="color:#98C379;">table</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">表名称（</span></span>
<span class="line"><span style="color:#ABB2BF;">  列名 </span><span style="color:#98C379;">数据类型</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">comment</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;备注’,</span></span>
<span class="line"><span style="color:#98C379;">  列名 数据类型 ,</span></span>
<span class="line"><span style="color:#98C379;">  …</span></span>
<span class="line"><span style="color:#98C379;">）</span></span>
<span class="line"><span style="color:#98C379;"># 显示表中的记录</span></span>
<span class="line"><span style="color:#98C379;">select * from 表名</span></span>
<span class="line"><span style="color:#98C379;"># 数据传入命令</span></span>
<span class="line"><span style="color:#98C379;">load data local infile &quot;文件名&quot; into table 表名</span></span>
<span class="line"><span style="color:#98C379;"># 表的详细描述</span></span>
<span class="line"><span style="color:#98C379;">describe tablename</span></span>
<span class="line"><span style="color:#98C379;"># 查询当前表结构</span></span>
<span class="line"><span style="color:#98C379;">desc 表名称</span></span>
<span class="line"><span style="color:#98C379;"># 查询表详细结构</span></span>
<span class="line"><span style="color:#98C379;">show create table 表名称;</span></span>
<span class="line"><span style="color:#98C379;">或</span></span>
<span class="line"><span style="color:#98C379;">show full columns from 表名称;</span></span>
<span class="line"></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br></div></div><hr><h3 id="方式1-mysql-提供的客户端命令工具" tabindex="-1">方式1：MySQL 提供的客户端命令工具 <a class="header-anchor" href="#方式1-mysql-提供的客户端命令工具" aria-hidden="true">#</a></h3><p>点击键盘按键<code>win</code>(四个正方形合成一个的图标按键)，呼出应用相关(我这里是win11系统)</p><p><img src="`+B+'" alt="khd1.jpg"></p><p>双击打开，输入密码</p><p><img src="'+u+`" alt="yx2.jpg"></p><hr><h3 id="方式2-系统自带的命令行工具执行命令" tabindex="-1">方式2：系统自带的命令行工具执行命令 <a class="header-anchor" href="#方式2-系统自带的命令行工具执行命令" aria-hidden="true">#</a></h3><p>指令：<code>mysql [-h 127.0.0.1] [-P 3306] -u root -p</code></p><p>或者：<code>mysql -uroot -p</code></p><p>如果没有配置mysql的环境变量</p><p>执行以上指令会提示：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#98C379;">&#39;mysql&#39;</span><span style="color:#ABB2BF;"> 不是内部或外部命令，也不是可运行的程序</span></span>
<span class="line"><span style="color:#ABB2BF;">或批处理文件。</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p>注意：要想在任意目录下执行上面的命令，就必须得配置PATH 环境变量</p></blockquote><h4 id="配置-mysql-全局环境变量" tabindex="-1">配置 MySQL 全局环境变量 <a class="header-anchor" href="#配置-mysql-全局环境变量" aria-hidden="true">#</a></h4><p>配置环境变量：打开 <code>我的电脑(此电脑)</code> -&gt; 鼠标<code>右键</code> -&gt; 选择 <code>属性</code> -&gt; 找到 <code>高级系统设置</code> -&gt; 选择 <code>环境变量</code></p><p><img src="`+h+'" alt="khd3.jpg"></p><p>双击或者单击选择 <code>Path</code>，点击 <code>编辑</code></p><p><img src="'+g+'" alt="khd4.jpg"></p><p>找到 MySQL 服务端的安装路径：<code>C:\\Program Files\\MySQL\\MySQL Server 8.0\\bin</code></p><p><img src="'+F+'" alt="在这里插入图片描述"></p><p>将这个路径配置到 <code>Path</code> 之中</p><p><img src="'+_+'" alt="在这里插入图片描述"></p><p>来到打开的配置环境变量的窗口，全部点击 <code>确定</code></p><p>现在就能够直接用系统管理员身份运行cmd或者Powershell指令打开 MySQL 了，指令：<code>mysql -uroot -p</code></p><hr><h3 id="方式3-navicat-premium数据库图形化界面管理软件-收费" tabindex="-1">方式3：Navicat Premium数据库图形化界面管理软件(收费) <a class="header-anchor" href="#方式3-navicat-premium数据库图形化界面管理软件-收费" aria-hidden="true">#</a></h3><hr><h3 id="方式4" tabindex="-1">方式4 <a class="header-anchor" href="#方式4" aria-hidden="true">#</a></h3><h2 id="卸载mysql数据库" tabindex="-1">卸载MySQL数据库 <a class="header-anchor" href="#卸载mysql数据库" aria-hidden="true">#</a></h2><p>首先调出系统服务，<code>win + R</code> 打开运行，输入 <code>services.msc</code> ，点击 <code>确定</code></p><p><img src="'+C+'" alt="khd7.jpg"></p><p>找到<code>MySQL80</code>服务，右键点击停止</p><p><img src="'+f+`" alt="xz1.png"></p><p>最后打开 <code>控制面板</code>，选择 <code>卸载程序</code> 卸载 MySQL 相关的组件</p><h2 id="可能遇到的问题" tabindex="-1">可能遇到的问题 <a class="header-anchor" href="#可能遇到的问题" aria-hidden="true">#</a></h2><p><strong>（1）使用数据库管理工具连接时报 <code>Plugin caching_sha2_password could not be loaded:********</code></strong></p><p>MySQL 新版默认使用 <code>caching_sha2_password</code> 作为身份验证插件，而旧版是使用 <code>mysql_native_password</code>，当连接 MySQL 时报错<code>plugin caching_sha2_password could not be loaded</code>时，可换回旧版插件。</p><p>解决方案：</p><p>命令行登录 mysql 之后，修改用户的身份验证插件</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;"># 修改 </span><span style="color:#C678DD;">root</span><span style="color:#ABB2BF;"> 用户的身份验证插件为 mysql_native_password</span></span>
<span class="line"><span style="color:#C678DD;">ALTER</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">USER</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;root&#39;</span><span style="color:#ABB2BF;">@</span><span style="color:#98C379;">&#39;localhost&#39;</span><span style="color:#ABB2BF;"> IDENTIFIED </span><span style="color:#C678DD;">WITH</span><span style="color:#ABB2BF;"> mysql_native_password </span><span style="color:#C678DD;">BY</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;123456&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;"># 刷新</span></span>
<span class="line"><span style="color:#ABB2BF;">FLUSH PRIVILEGES；</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>重新连接</p><hr><p>参考博客：<br><a href="https://blog.csdn.net/qq_54202620/article/details/122729704" target="_blank" rel="noreferrer">SQLyog错误号码 plugin caching_sha2_password could not be loaded</a></p>`,95),q=[L];function v(S,E,w,x,k,M){return a(),n("div",null,q)}const D=s(A,[["render",v]]);export{j as __pageData,D as default};
